    self.rankST = self:getChildWindow("LiftingSimulatorMainRank-Rank", GUIType.StaticText)
    self.nameST = self:getChildWindow("LiftingSimulatorMainRank-Name", GUIType.StaticText)
    self.muscleST = self:getChildWindow("LiftingSimulatorMainRank-Muscle", GUIType.StaticText)
    self.fameST = self:getChildWindow("LiftingSimulatorMainRank-Fame", GUIType.StaticText)
    self.killST = self:getChildWindow("LiftingSimulatorMainRank-Kill", GUIType.StaticText)
    self.stageST = self:getChildWindow("LiftingSimulatorMainRank-Stage", GUIType.StaticText)

    self.rankST:SetText(Lang:getString("Rank"))
    self.nameST:SetText(Lang:getString("Name"))
    self.muscleST:SetText(Lang:getString("Muscle"))
    self.fameST:SetText(Lang:getString("Fame"))
    self.killST:SetText(Lang:getString("Kill"))
    self.stageST:SetText(Lang:getString("Stage"))

    self.rankBg = self:getChildWindow("LiftingSimulatorMainRank-Bg", GUIType.StaticImage)
    self.rankBg:registerEvent(GUIEvent.Click, function()
        self:onContractionOrRelease()
    end)

    self.meRankText = self:getChildWindow("LiftingSimulatorMainRank-MeRankText", GUIType.StaticText)
    self.meNameText = self:getChildWindow("LiftingSimulatorMainRank-MeNameText", GUIType.StaticText)
    self.meMuscleText = self:getChildWindow("LiftingSimulatorMainRank-MeMuscleText", GUIType.StaticText)
    self.meFameText = self:getChildWindow("LiftingSimulatorMainRank-MeFameText", GUIType.StaticText)
    self.meKillText = self:getChildWindow("LiftingSimulatorMainRank-MeKillText", GUIType.StaticText)
    self.meStageText = self:getChildWindow("LiftingSimulatorMainRank-MeStageText", GUIType.StaticText)

    self.meRankIcon = self:getChildWindow("LiftingSimulatorMainRank-MeRankIcon", GUIType.StaticImage)
    self.meStageIcon = self:getChildWindow("LiftingSimulatorMainRank-MeStageIcon", GUIType.StaticImage)

    self.meRankBg = self:getChildWindow("LiftingSimulatorMainRank-MeBg", GUIType.StaticImage)
    self.meRankBg:registerEvent(GUIEvent.Click, function()
        self:onContractionOrRelease()
    end)

    self.otherRank = self:getChildWindow("LiftingSimulatorMainRank-Other", GUIType.Layout)
    self.otherRank:SetVisible(false)
    --self.otherRank:SetYPosition({ 0, 25 })
    self.otherRankList = self:getChildWindow("LiftingSimulatorMainRank-OtherRank", GUIType.List)

    --用于显示个人排行榜信息
    self:registerEvent(S2CLSMeRankUpdate, function(data)
        self:onMeRankUpdate(data)
    end)

    --用于显示整个排行榜信息
    self:registerEvent(S2CLSAllOtherRankUpdate, function(data)
        self:onAllOtherRankUpdate(data)
    end)
end

function UIMainControlRank:onMeRankUpdate(data)
    if not self:isLoad() then
        return
    end

    local builder = json.decode(data)

    self.meRankText:SetText(tostring(builder.rank))
    self.meNameText:SetText(Utility.toAbbreviateString(tostring(builder.name)))
    self.meMuscleText:SetText(Utility.toKMBString(tostring(builder.muscle), 2))
    self.meFameText:SetText(Lang:getString(tostring(builder.fame)))
    self.meKillText:SetText(Utility.toKMBString(tostring(builder.kill), 2))
    self.meStageText:SetText(Lang:getString(tostring(builder.stage)))

end

function UIMainControlRank:onAllOtherRankUpdate(data)
    local builder = json.decode(data)
    self.allRank = builder
    self:updateItemRank()
end

function UIMainControlRank:isMainLayout()
    return true
end

function UIMainControlRank:updateItemRank()

    --self.otherRankList:ClearAllItem()

    local i = 1
    for key, value in pairs(self.allRank) do

        if self.playerNum < i then

            local strIcon = string.format("LiftingSimulatorMainRank-Item-Icon%d", i)
            self.ivIconItem[i] = GUIManager:createGUIWindow(GUIType.StaticImage, strIcon)
            self.ivIconItem[i]:SetArea({ 0, 0 }, { 0, 0 }, { 0, 380 }, { 0, 25 })
            self.ivIconItem[i]:SetImage("set:LiftingSimulatorMainRank1.json image:bg2")
            self.ivIconItem[i]:registerEvent(GUIEvent.Click, function()
                self:onContractionOrRelease()
            end)
            self.ivIconItem[i]:SetVisible(true)
            self.otherRankList:AddItem(self.ivIconItem[i], false)

            local strRank = string.format("LiftingSimulatorMainRank-Item-Rank%d", i)
            self.tvRankItem[i] = GUIManager:createGUIWindow(GUIType.StaticText, strRank)
            self.tvRankItem[i]:SetArea({ 0, 0 }, { 0, 0 }, { 0, 60 }, { 0, 25 })
            self.tvRankItem[i]:SetFont(GUIFontManager:Instance():GetFont("HT12"))
            self.tvRankItem[i]:SetText(tostring(value.rank))
            self.tvRankItem[i]:SetTextHorzAlign(HorizontalAlignment.Center)
            --self.otherRankList:AddItem(rankItem, false)
            self.ivIconItem[i]:AddChildWindow(self.tvRankItem[i])

            local strName = string.format("LiftingSimulatorMainRank-Item-Name%d", i)
