            self.ivIconItem[i]:AddChildWindow(self.tvMuscleItem[i])

            local strFame = string.format("LiftingSimulatorMainRank-Item-Fame%d", i)
            self.tvFameItem[i] = GUIManager:createGUIWindow(GUIType.StaticText, strFame)
