            self.tvFameItem[i]:SetText(Lang:getString(tostring(value.fame)))
            self.tvFameItem[i]:SetTextHorzAlign(HorizontalAlignment.Center)
            --self.otherRankList:AddItem(fameItem, false)
            self.ivIconItem[i]:AddChildWindow(self.tvFameItem[i])

            local strKill = string.format("LiftingSimulatorMainRank-Item-Kill%d", i)
            self.tvKillItem[i] = GUIManager:createGUIWindow(GUIType.StaticText, strKill)
            self.tvKillItem[i]:SetArea({ 0, 260 }, { 0, 0 }, { 0, 60 }, { 0, 25 })
            self.tvKillItem[i]:SetFont(GUIFontManager:Instance():GetFont("HT12"))
            self.tvKillItem[i]:SetText(Utility.toKMBString(tostring(value.kill), 2))
            self.tvKillItem[i]:SetTextHorzAlign(HorizontalAlignment.Center)
            --self.otherRankList:AddItem(killItem, false)
            self.ivIconItem[i]:AddChildWindow(self.tvKillItem[i])

            local strStage = string.format("LiftingSimulatorMainRank-Item-Stage%d", i)
            self.tvStageItem[i] = GUIManager:createGUIWindow(GUIType.StaticText, strStage)
            self.tvStageItem[i]:SetArea({ 0, 320 }, { 0, 0 }, { 0, 60 }, { 0, 25 })
            self.tvStageItem[i]:SetFont(GUIFontManager:Instance():GetFont("HT12"))
            self.tvStageItem[i]:SetText(Lang:getString(tostring(value.stage)))
            self.tvStageItem[i]:SetTextHorzAlign(HorizontalAlignment.Center)
            --self.otherRankList:AddItem(stageItem, false)
            self.ivIconItem[i]:AddChildWindow(self.tvStageItem[i])

        else

            self.ivIconItem[i]:SetVisible(true)
            self.tvRankItem[i]:SetText(tostring(value.rank))
            self.tvNameItem[i]:SetText(Utility.toAbbreviateString(tostring(value.name)))
