function UIMainControlRank:onContractionOrRelease()

    --HostApi.log("++++++++++++++++++++++++++++++")
    if not self:isLoad() then
        return
    end

    if self.selectMode == 1 then

        self.selectMode = 2
        self.otherRank:SetVisible(true)
        self.meRankIcon:SetImage("set:LiftingSimulatorMainRank1.json image:xiangshang")
        self.meStageIcon:SetImage("set:LiftingSimulatorMainRank1.json image:xiangshang")
        --self.otherRankList:ResetScroll()
        --self:updateItemRank()
        --self.meRankBg:SetVisible(false)

    else

        self.selectMode = 1
        self.otherRank:SetVisible(false)
        self.meRankIcon:SetImage("set:LiftingSimulatorMainRank1.json image:xiangxia")
        self.meStageIcon:SetImage("set:LiftingSimulatorMainRank1.json image:xiangxia")
        --self.meRankBg:SetVisible(true)
    end

end

return UIMainControlRank
